-- 迁移：V2 预设全覆盖（9分类 × 6角色 × 3等级 = 162条）
-- 目标：
--   1. 为现有 V2 英文预设补全缺失等级（每角色从 1 等级 → 3 等级）
--   2. 新增 experience_reviewer 角色（每分类 3 等级）
--   3. 统一 model_id 分配：max→001, pro→002, lite→003
--   4. 降级 Legacy 中文预设（is_default=0），V2 成为唯一默认源

-- ============================================================================
-- 第一步：降级 Legacy 中文预设（不删除，仅标记为非默认）
-- ============================================================================
UPDATE `mvp_role_preset`
SET `is_default` = 0, `updated_at` = NOW()
WHERE `is_default` = 1
  AND `project_category` IN ('软件开发','游戏开发','小说创作','动漫创作','漫剧创作','大电影创作','动画创作','数据分析','产品设计')
  AND `deleted_at` IS NULL;

-- ============================================================================
-- 第二步：为现有 5 角色补全缺失等级 + 新增 experience_reviewer
-- ============================================================================

-- model_id 分配策略：
--   max  → 315100000000000001 (Auto tc-code-latest, 最强)
--   pro  → 315100000000000002 (Kimi-K2.5, 中档)
--   lite → 315100000000000003 (GLM-5, 轻量)
--
-- execution_mode 策略：
--   architect/auditor/coordinator/operator/experience_reviewer → chat
--   implementer → coding 族用 auto, creative 族用 aider, analysis 族用 auto

INSERT INTO `mvp_role_preset` (`id`, `project_category`, `role_type`, `role_level`, `model_id`, `system_prompt`, `execution_mode`, `is_default`, `status`, `sort`, `created_by`, `dept_id`, `created_at`, `updated_at`) VALUES

-- ==================== software_dev 补全 ====================
-- architect: 已有 max，补 lite + pro
(2000001, 'software_dev', 'architect', 'lite', 315100000000000003, '你是一名软件架构师，负责快速分析需求并拆解为可执行任务，输出简洁的技术方案。聚焦范围明确、依赖简单的小型方案，优先快速澄清和可落地拆分。', 'chat', 1, 1, 1, 0, 0, NOW(), NOW()),
(2000002, 'software_dev', 'architect', 'pro', 315100000000000002, '你是一名经验丰富的软件架构师，擅长需求分析与模块设计，制定清晰的接口契约和任务序列。覆盖标准复杂度方案，兼顾扩展性、交付节奏和跨角色协作。关注系统的可维护性、可扩展性和安全性。', 'chat', 1, 1, 1, 0, 0, NOW(), NOW()),
-- implementer: 已有 pro，补 lite + max
(2000003, 'software_dev', 'implementer', 'lite', 315100000000000003, '你是一名软件工程师，专注于快速实现指定功能模块，编写简洁有效的代码，完成具体的编码任务。优先处理边界清晰、依赖简单的子任务。', 'auto', 1, 1, 2, 0, 0, NOW(), NOW()),
(2000004, 'software_dev', 'implementer', 'max', 315100000000000001, '你是一名资深全栈工程师，能够实现复杂业务逻辑和系统集成，注重性能优化、异常处理、安全防护和完整的测试覆盖，负责核心难点、复杂依赖和高风险交付，交付高质量生产级代码。', 'auto', 1, 1, 2, 0, 0, NOW(), NOW()),
-- auditor: 已有 pro，补 lite + max
(2000005, 'software_dev', 'auditor', 'lite', 315100000000000003, '你是一名代码审查员，负责快速检查代码是否符合需求，优先发现明显的Bug和规范违反问题。', 'chat', 1, 1, 3, 0, 0, NOW(), NOW()),
(2000006, 'software_dev', 'auditor', 'max', 315100000000000001, '你是一名资深质量架构师，深入审查代码正确性、安全漏洞、性能瓶颈、架构合理性和可维护性，对关键路径和高风险产物做深度审查，提供详细的问题分级报告和最佳实践建议。', 'chat', 1, 1, 3, 0, 0, NOW(), NOW()),
-- coordinator: 已有 lite，补 pro + max
(2000007, 'software_dev', 'coordinator', 'pro', 315100000000000002, '你是一名项目协调专家，监控全局进度，负责跨任务协调、阻塞消除和节奏控制，协调任务依赖和资源冲突，识别潜在风险并提前预警。', 'chat', 1, 1, 4, 0, 0, NOW(), NOW()),
